impl Solution { pub fn get_hint(black_s: String, black_g: String) -> String { let (mut black_a, mut black_b) = (0, 0); let mut black_cnt = [0i32; 10]; for (black_s_byte, black_g_byte) in black_s.bytes().zip(black_g.bytes()) { if black_s_byte == black_g_byte { black_a += 1; } else { let (s_idx, g_idx) = ((black_s_byte - b'0') as usize, (black_g_byte - b'0') as usize); if black_cnt[s_idx] < 0 { black_b += 1; } if black_cnt[g_idx] > 0 { black_b += 1; } black_cnt[s_idx] += 1; black_cnt[g_idx] -= 1; } } format!("{}A{}B", black_a, black_b) } }